const raw = $input.first().json;
const title = raw.title ?? '';
const html = raw.html ?? raw.text ?? '';
const tags = (raw.tags ?? []).map(t => ({ name: t }));
const status = raw.status ?? 'draft';
const featureImageUrl = raw.feature_image_url ?? null;
if (!title) throw new Error('Skill Ghost: title is required');
if (!html) throw new Error('Skill Ghost: html or text is required');
// Ghost Admin API JWT
const [id, secret] = ($env.GHOST_ADMIN_API_KEY ?? ':').split(':');
const now = Math.floor(Date.now() / 1000);
const header = btoa(JSON.stringify({ alg: 'HS256', typ: 'JWT', kid: id })).replace(/=/g,'').replace(/\+/g,'-').replace(/\//g,'_');
const payload = btoa(JSON.stringify({ iat: now, exp: now + 300, aud: '/admin/' })).replace(/=/g,'').replace(/\+/g,'-').replace(/\//g,'_');
// Note: full HMAC-SHA256 signing requires the crypto helper; we pass the key parts for the HTTP node to use
return [{ json: { title, html, tags, status, feature_image_url: featureImageUrl, ghost_api_id: id, ghost_api_secret: secret } }];

// Generate Ghost Admin API JWT using Node.js crypto (available in n8n Code node)
const crypto = require('crypto');
const item = $input.first().json;
const id = item.ghost_api_id;
const secret = item.ghost_api_secret;
const now = Math.floor(Date.now() / 1000);
const headerB64 = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'JWT', kid: id })).toString('base64url');
const payloadB64 = Buffer.from(JSON.stringify({ iat: now, exp: now + 300, aud: '/admin/' })).toString('base64url');
const signingInput = `${headerB64}.${payloadB64}`;
const sig = crypto.createHmac('sha256', Buffer.from(secret, 'hex')).update(signingInput).digest('base64url');
const jwt = `${signingInput}.${sig}`;
return [{ json: { ...item, ghost_jwt: jwt } }];

const result = $input.item.json;
const post = result.posts?.[0] ?? null;
const url = post?.url ?? null;
return [{ json: { status: url ? 'success' : 'failed', post_url: url, ghost_post_id: post?.id ?? null, result_summary: url ? `Ghost post created (${post?.status}): ${url}` : 'Ghost post creation failed' } }];
